// Extract channel from Google Drive path
const file = $input.item.json;
const path = file.name;
const parentFolders = file.parents || [];

// Determine channel from folder structure
// You'll create folders: Health-Hacks/queue and MONEYSTACK/queue
let channel = "UNKNOWN";

// Check parent folder names
if (path.toLowerCase().includes("health") || path.toLowerCase().includes("hacks")) {
  channel = "HEALTH_HACKS";
} else if (path.toLowerCase().includes("moneystack") || path.toLowerCase().includes("money")) {
  channel = "MONEYSTACK";
}

// Only process video files
const ext = path.split('.').pop().toLowerCase();
if (!['mp4', 'mov', 'avi', 'webm'].includes(ext)) {
  throw new Error("Not a video file - skipping");
}

// Generate video ID
const timestamp = new Date().toISOString().split('T')[0].replace(/-/g, '');
const randomId = Math.random().toString(36).substring(2, 6);
const videoId = `${channel.toLowerCase()}-${timestamp}-${randomId}`;

const channelContexts = {
  "HEALTH_HACKS": {
    "niche": "Pain relief, energy, sleep, stress, gut health",
    "audience": "Office workers, health-conscious 25-45",
    "tone": "Science-backed, practical, no BS",
    "products": ["calmorarelief.com"]
  },
  "MONEYSTACK": {
    "niche": "Money psychology, savings, financial health",
    "audience": "Young professionals 18-35",
    "tone": "Real talk, relatable, honest",
    "products": []
  }
};

return {
  videoId: videoId,
  channel: channel,
  channelContext: channelContexts[channel],
  originalFilename: file.name,
  driveFileId: file.id,
  fileSize: parseInt(file.size || 0),
  detectedAt: new Date().toISOString()
};

// Build complete metadata JSON
const videoId = $node["Extract Channel"].json.videoId;
const channel = $node["Extract Channel"].json.channel;
const transcript = $node["Transcribe Audio"].json.transcription;
const duration = $node["Get Video Metadata"].json.duration;
const resolution = $node["Get Video Metadata"].json.resolution;
const fileSize = $node["Extract Channel"].json.fileSize;

// Get humanized content
const tiktok = $node["Humanize TikTok"].json;
const instagram = $node["Humanize Instagram"].json;
const youtube = $node["Humanize YouTube"].json;

const metadata = {
  video_id: videoId,
  channel: channel,
  original_filename: $node["Extract Channel"].json.originalFilename,
  drive_file_id: $node["Extract Channel"].json.driveFileId,

  video_info: {
    duration: duration,
    resolution: resolution,
    file_size_mb: Math.round(fileSize / 1048576 * 10) / 10
  },

  transcription: transcript,

  content: {
    tiktok: {
      title: tiktok.tiktokTitle,
      caption: tiktok.tiktokCaption,
      hashtags: tiktok.tiktokHashtags
    },
    instagram: {
      title: instagram.instagramTitle,
      caption: instagram.instagramCaption,
      hashtags: instagram.instagramHashtags
    },
    youtube: {
      title: youtube.youtubeTitle,
      description: youtube.youtubeDescription,
      tags: youtube.youtubeTags
    }
  },

  status: "ready_to_upload",
  created_at: new Date().toISOString()
};

return { json: metadata };

// Save metadata to file
const fs = require('fs');
const path = require('path');

const metadata = $input.item.json;
const videoId = metadata.video_id;
const outputDir = '/workspace/.state/videos';

// Create directory if needed
if (!fs.existsSync(outputDir)) {
  fs.mkdirSync(outputDir, { recursive: true });
}

const outputPath = path.join(outputDir, `${videoId}.json`);
fs.writeFileSync(outputPath, JSON.stringify(metadata, null, 2));

return {
  json: {
    ...metadata,
    metadata_saved: outputPath
  }
};

